import React, { useState } from 'react';
import { DndContext, closestCenter } from '@dnd-kit/core';
import { SortableContext, useSortable, arrayMove, horizontalListSortingStrategy } from '@dnd-kit/sortable';
import { CSS } from '@dnd-kit/utilities';

function Column({ id }) {
  const { attributes, listeners, setNodeRef, transform, transition } = useSortable({ id });
  const style = {
    transform: CSS.Transform.toString(transform),
    transition,
    width: 200,
    height: 300,
    backgroundColor: '#f0f0f0',
    border: '1px solid #ccc',
    borderRadius: 4,
    margin: '0 10px',
    padding: 10,
  };
  return <div ref={setNodeRef} style={style} {...attributes} {...listeners}><h3>Column {id}</h3></div>;
}

function App() {
  const [columns, setColumns] = useState(['A', 'B', 'C']);

  function handleDragEnd(event) {
    const { active, over } = event;
    if (over && active.id !== over.id) {
      setColumns((columns) => {
        const oldIndex = columns.indexOf(active.id);
        const newIndex = columns.indexOf(over.id);
        return arrayMove(columns, oldIndex, newIndex);
      });
    }
  }

  return (
    <DndContext collisionDetection={closestCenter} onDragEnd={handleDragEnd}>
      <div style={{ display: 'flex', padding: 20 }}>
        <SortableContext items={columns} strategy={horizontalListSortingStrategy}>
          {columns.map(id => <Column key={id} id={id} />)}
        </SortableContext>
      </div>
    </DndContext>
  );
}

export default App;
